<template>
	<div class="home_view">
		<div class="projectTitle">欢迎使用 {{projectName}}</div>
		<div class="count_list">
			<el-collapse-transition v-if="btnAuth('article','首页总数')">
				<el-card v-show="countTypeList.closearticleCountType" class="card_view">
					<template #header>
						<div class="index_card_head">
							<div class="card_head_title">
								帖子
							</div>
							<div class="card_head_right">
								<el-icon @click="countTypeClick('hiddenarticleCountType')" class="showIcons"
									:class="countTypeList.hiddenarticleCountType?'showIcons1':''">
									<ArrowUpBold />
								</el-icon>
								<el-icon @click="countTypeClick('closearticleCountType')" class="closeIcons">
									<CloseBold />
								</el-icon>
							</div>
							
						</div>
					</template>
					<el-collapse-transition>
						<div class="count_item" v-show="countTypeList.hiddenarticleCountType">
							<div class="count_title">帖子总数</div>
							<div class="count_num">{{articleCount}}</div>
						</div>
					</el-collapse-transition>
				</el-card>
			</el-collapse-transition>
			<el-collapse-transition v-if="btnAuth('report','首页总数')">
				<el-card v-show="countTypeList.closereportCountType" class="card_view">
					<template #header>
						<div class="index_card_head">
							<div class="card_head_title">
								举报信息
							</div>
							<div class="card_head_right">
								<el-icon @click="countTypeClick('hiddenreportCountType')" class="showIcons"
									:class="countTypeList.hiddenreportCountType?'showIcons1':''">
									<ArrowUpBold />
								</el-icon>
								<el-icon @click="countTypeClick('closereportCountType')" class="closeIcons">
									<CloseBold />
								</el-icon>
							</div>
							
						</div>
					</template>
					<el-collapse-transition>
						<div class="count_item" v-show="countTypeList.hiddenreportCountType">
							<div class="count_title">举报信息总数</div>
							<div class="count_num">{{reportCount}}</div>
						</div>
					</el-collapse-transition>
				</el-card>
			</el-collapse-transition>
			<el-collapse-transition v-if="btnAuth('user','首页总数')">
				<el-card v-show="countTypeList.closeuserCountType" class="card_view">
					<template #header>
						<div class="index_card_head">
							<div class="card_head_title">
								用户
							</div>
							<div class="card_head_right">
								<el-icon @click="countTypeClick('hiddenuserCountType')" class="showIcons"
									:class="countTypeList.hiddenuserCountType?'showIcons1':''">
									<ArrowUpBold />
								</el-icon>
								<el-icon @click="countTypeClick('closeuserCountType')" class="closeIcons">
									<CloseBold />
								</el-icon>
							</div>
							
						</div>
					</template>
					<el-collapse-transition>
						<div class="count_item" v-show="countTypeList.hiddenuserCountType">
							<div class="count_title">用户总数</div>
							<div class="count_num">{{userCount}}</div>
						</div>
					</el-collapse-transition>
				</el-card>
			</el-collapse-transition>
			<el-collapse-transition v-if="btnAuth('feedback','首页总数')">
				<el-card v-show="countTypeList.closefeedbackCountType" class="card_view">
					<template #header>
						<div class="index_card_head">
							<div class="card_head_title">
								用户反馈
							</div>
							<div class="card_head_right">
								<el-icon @click="countTypeClick('hiddenfeedbackCountType')" class="showIcons"
									:class="countTypeList.hiddenfeedbackCountType?'showIcons1':''">
									<ArrowUpBold />
								</el-icon>
								<el-icon @click="countTypeClick('closefeedbackCountType')" class="closeIcons">
									<CloseBold />
								</el-icon>
							</div>
							
						</div>
					</template>
					<el-collapse-transition>
						<div class="count_item" v-show="countTypeList.hiddenfeedbackCountType">
							<div class="count_title">用户反馈总数</div>
							<div class="count_num">{{feedbackCount}}</div>
						</div>
					</el-collapse-transition>
				</el-card>
			</el-collapse-transition>
		</div>
		<div class="card_list">
			<el-collapse-transition v-if="btnAuth('article','首页统计')">
				<el-card v-show="cardTypeList.closearticleChartType1" class="card_view">
					<template #header>
						<div class="index_card_head">
							<div class="card_head_title">
								帖子
							</div>
							<div class="card_head_right">
								<el-icon @click="cardTypeClick('hiddenarticleChartType1')" class="showIcons"
									:class="cardTypeList.hiddenarticleChartType1?'showIcons1':''">
									<ArrowUpBold />
								</el-icon>
								<el-icon @click="cardTypeClick('closearticleChartType1')" class="closeIcons">
									<CloseBold />
								</el-icon>
							</div>
						</div>
					</template>
					<el-collapse-transition>
						<div class="card_item" v-show="cardTypeList.hiddenarticleChartType1">
							<div id="articlecategoryEchart1" style="width: 100%;height: 400px;"></div>
						</div>
					</el-collapse-transition>
				</el-card>
			</el-collapse-transition>
			<el-collapse-transition v-if="btnAuth('article','首页统计')">
				<el-card v-show="cardTypeList.closearticleChartType2" class="card_view">
					<template #header>
						<div class="index_card_head">
							<div class="card_head_title">
								帖子
							</div>
							<div class="card_head_right">
								<el-icon @click="cardTypeClick('hiddenarticleChartType2')" class="showIcons"
									:class="cardTypeList.hiddenarticleChartType2?'showIcons1':''">
									<ArrowUpBold />
								</el-icon>
								<el-icon @click="cardTypeClick('closearticleChartType2')" class="closeIcons">
									<CloseBold />
								</el-icon>
							</div>
						</div>
					</template>
					<el-collapse-transition>
						<div class="card_item" v-show="cardTypeList.hiddenarticleChartType2">
							<div id="articlefabushijianEchart2" style="width: 100%;height: 400px;"></div>
						</div>
					</el-collapse-transition>
				</el-card>
			</el-collapse-transition>
		</div>
	</div>
</template>

<script setup>
	import {
		inject,
		nextTick,
		ref,
		getCurrentInstance
	} from 'vue';
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	const projectName = context.$project.projectName
	const countTypeList = ref({
	})
	const getCountList=()=>{
		countTypeList.value.closearticleCountType = true
		countTypeList.value.hiddenarticleCountType = true
		if(btnAuth('article','首页总数')){
			getarticleCount()
		}
		countTypeList.value.closereportCountType = true
		countTypeList.value.hiddenreportCountType = true
		if(btnAuth('report','首页总数')){
			getreportCount()
		}
		countTypeList.value.closeuserCountType = true
		countTypeList.value.hiddenuserCountType = true
		if(btnAuth('user','首页总数')){
			getuserCount()
		}
		countTypeList.value.closefeedbackCountType = true
		countTypeList.value.hiddenfeedbackCountType = true
		if(btnAuth('feedback','首页总数')){
			getfeedbackCount()
		}
	}
	const articleCount = ref(0)
	const getarticleCount = () => {
		context?.$http({
			url:'article/count',
			method: 'get'
		}).then(res=>{
			articleCount.value = res.data.data
		})
	}
	const reportCount = ref(0)
	const getreportCount = () => {
		context?.$http({
			url:'report/count',
			method: 'get'
		}).then(res=>{
			reportCount.value = res.data.data
		})
	}
	const userCount = ref(0)
	const getuserCount = () => {
		context?.$http({
			url:'user/count',
			method: 'get'
		}).then(res=>{
			userCount.value = res.data.data
		})
	}
	const feedbackCount = ref(0)
	const getfeedbackCount = () => {
		context?.$http({
			url:'feedback/count',
			method: 'get'
		}).then(res=>{
			feedbackCount.value = res.data.data
		})
	}
	const countTypeClick = (e) => {
		countTypeList.value[e] = !countTypeList.value[e]
	}
	const init=()=>{
		getCountList()
		getCardList()
	}
	//权限验证
	const btnAuth = (e,a)=>{
		return context?.$toolUtil.isAuth(e,a)
	}
	let echarts = inject("echarts")
	const cardTypeClick = (e) =>{
		cardTypeList.value[e] = !cardTypeList.value[e]
		setTimeout(()=>{
			getCardList()
		},1000)
	}
	const cardTypeList = ref({
		closearticleChartType1: true,
		hiddenarticleChartType1: true,
		closearticleChartType2: true,
		hiddenarticleChartType2: true,
	})
	const getCardList = () => {
		if(btnAuth('article','首页统计')){
			getarticleChart1()
		}
		if(btnAuth('article','首页统计')){
			getarticleChart2()
		}
	}
	const getarticleChart1 = () => {
		nextTick(()=>{
			var categoryEchart1 = echarts.init(document.getElementById("articlecategoryEchart1"),'macarons');
			context?.$http({
				url: "article/group/category",
				method: "get",
			}).then(obj=>{
				let res = obj.data.data
				let xAxis = [];
				let yAxis = [];
				let pArray = []
				for(let i=0;i<res.length;i++){
				    xAxis.push(res[i].category);
				    yAxis.push(parseFloat((res[i].total)));
				    pArray.push({
				        value: parseFloat((res[i].total)),
				        name: res[i].category
				    })
				}
				var option = {};
                option = {
                    title: {
                        text: '各内容分类数据统计',
                        left: 'center'
                    },
                    legend: {
                        orient: 'vertical',
                        left: 'left'
                    },
                    tooltip: {
						trigger: 'item',
						formatter: '{b} : {c} ({d}%)'
                    },
                    series: [
                        {
                            type: 'pie',
                            radius: '55%',
                            center: ['50%', '60%'],
                            data: pArray,
                            emphasis: {
                                itemStyle: {
                                    shadowBlur: 10,
                                    shadowOffsetX: 0,
									shadowColor: 'rgba(0, 0, 0, 0.5)'
                                }
                            }
                        }
                    ]
                };
				categoryEchart1.clear()
				// 使用刚指定的配置项和数据显示图表。
				categoryEchart1.setOption(option);
				//根据窗口的大小变动图表
				categoryEchart1.resize();
			})
		})
	}
	const getarticleChart2 = () => {
		nextTick(()=>{
			var fabushijianEchart2 = echarts.init(document.getElementById("articlefabushijianEchart2"),'macarons');
			context?.$http({
				url: "article/group/fabushijian",
				method: "get",
			}).then(obj=>{
				let res = obj.data.data
				let xAxis = [];
				let yAxis = [];
				let pArray = []
				for(let i=0;i<res.length;i++){
				    xAxis.push(res[i].fabushijian);
				    yAxis.push(parseFloat((res[i].total)));
				    pArray.push({
				        value: parseFloat((res[i].total)),
				        name: res[i].fabushijian
				    })
				}
				var option = {};
                option = {
                    title: {
                        text: '日发帖量数据统计',
                        left: 'center'
                    },
                    tooltip: {
                      trigger: 'item',
                      formatter: '{b} : {c}'
                    },
                    xAxis: {
                        type: 'category',
                        data: xAxis,
                        axisLabel: {
                            rotate: 40
                        }
                    },
                    yAxis: {
                        type: 'value'
                    },
                    series: [{
                        data: yAxis,
                        type: 'bar'
                    }]
                };
				// 使用刚指定的配置项和数据显示图表。
				fabushijianEchart2.clear()
				fabushijianEchart2.setOption(option);
				//根据窗口的大小变动图表
				fabushijianEchart2.resize();
			})
		})
	}
	init()
</script>
<style lang="scss">
	.projectTitle{
		padding: 20px 0;
		margin: 20px 0 20px;
		color: #333;
		font-weight: bold;
		display: flex;
		width: 100%;
		font-size: 30px;
		justify-content: center;
		align-items: center;
		height: auto;
	}

	.showIcons {
		transition: transform 0.3s;
		margin-right: 10px;
	}

	.showIcons1 {
		transform: rotate(-180deg);
	}
	
	// 总数盒子
	.count_list{
		padding: 0 0 20px;
		display: flex;
		width: 100%;
		justify-content: center;
		align-items: flex-start;
		flex-wrap: wrap;
		// 总数card
		.card_view {
			border: 3px ridge #eee;
			border-radius: 0;
			box-shadow: 0px 0px 0px rgba(0,0,0,.12);
			margin: 0 1% 20px;
			width: 23%;
			box-sizing: border-box;
			height: auto;
			// card头部
			.el-card__header {
				border: 3px ridge #eee;
				background: linear-gradient(180deg, rgba(255,255,255,.6) 80%, rgba(202,210,231,1) 100%);
				width: 100%;
				border-width: 0 0 0px;
				// 头部盒子
				.index_card_head {
					display: flex;
					width: 100%;
					justify-content: space-between;
					align-items: center;
					height: 10px;
					// 标题
					.card_head_title {
						color: #333;
						font-size: 14px;
					}
					// 按钮盒子
					.card_head_right {
						display: flex;
						align-items: center;
						// 按钮
						.el-icon {
							cursor: pointer;
							color: #333;
							font-size: 20px;
						}
					}
				}
			}
			// body
			.el-card__body {
				padding: 0;
				background: linear-gradient(30deg, rgba(227,231,242,1) 0%, rgba(255,255,255,1) 20%, rgba(255,255,255,1) 80%, rgba(227,231,242,1) 100%);
				border-color: #eee;
				border-width: 0 1px 1px;
				border-style: solid;
				// body盒子
				.count_item{
					padding: 30px;
					flex-direction: column;
					display: flex;
					justify-content: center;
					align-items: center;
					text-align: center;
					// 总数标题
					.count_title{
						margin: 0 0px 0 0;
						color: #666;
						font-weight: 500;
						display: inline-block;
						font-size: 16px;
						line-height: 1.5;
					}
					// 总数数字
					.count_num{
						color: #c00;
						font-weight: 600;
						display: inline-block;
						font-size: 26px;
						line-height: 1.5;
					}
				}
			}
		}
	}
	// 首页盒子
	.home_view {
		padding: 0px 20px;
		margin: 0;
		background: url(http://clfile.zggen.cn/20240203/09a98f4852104a599055d47953ef0a23.png) no-repeat center top / 100% 100% !important;
		width: 100%;
		min-height: 100vh;
		height: auto;
	}
	// 统计图盒子
	.card_list {
		padding: 0 0 20px;
		display: flex;
		width: 100%;
		justify-content: space-between;
		align-items: flex-start;
		flex-wrap: wrap;
		// 统计图card
		.card_view {
			border: 3px ridge #eee;
			border-radius: 0;
			box-shadow: 0px 0px 0px rgba(0,0,0,.12);
			margin: 10px;
			width: calc(50% - 20px);
			box-sizing: border-box;
			height: auto;
			// 头部
			.el-card__header {
				border: 0px solid #eee;
				background: linear-gradient(180deg, rgba(255,255,255,.6) 80%, rgba(202,210,231,1) 100%);
				width: 100%;
				border-width: 0 0 0px;
				// 头部盒子
				.index_card_head {
					display: flex;
					width: 100%;
					justify-content: space-between;
					align-items: center;
					height: 10px;
					// 标题
					.card_head_title {
						color: #333;
						font-size: 14px;
					}
					// 按钮盒子
					.card_head_right {
						display: flex;
						align-items: center;
						// 按钮
						.el-icon{
							cursor: pointer;
							color: #333;
							font-size: 20px;
						}
					}
				}
			}
			// body
			.el-card__body {
				padding: 0;
				background: linear-gradient(30deg, rgba(227,231,242,1) 0%, rgba(255,255,255,1) 20%, rgba(255,255,255,1) 80%, rgba(227,231,242,1) 100%);
				border-color: #eee;
				border-width: 0 1px 1px;
				border-style: solid;
				// body盒子
				.card_item{
					padding: 10px;
					text-align: center;
				}
			}
		}
	}
</style>
